// MARK: - SecureSecretsManager.swift
// Manages API keys and secrets securely using iOS Keychain
// NEVER hardcode API keys, even "test" keys, in source code.

import Foundation
import Security

enum SecureSecretsError: Error, LocalizedStringErrorDescription {
    case keychainWriteFailed(OSStatus)
    case keychainReadFailed
    case keychainDeleteFailed(OSStatus)
    case missingEnvironmentVariable(String)
    case dataConversionFailed
    
    var errorDescription: String? {
        switch self {
        case .keychainWriteFailed(let status):
            return "Keychain write failed with status: \(status)"
        case .keychainReadFailed:
            return "Keychain read failed: item not found"
        case .keychainDeleteFailed(let status):
            return "Keychain delete failed with status: \(status)"
        case .missingEnvironmentVariable(let name):
            return "Missing environment variable: \(name)"
        case .dataConversionFailed:
            return "Failed to convert data to/from string"
        }
    }
}

protocol LocalizedStringErrorDescription: LocalizedError {}

// MARK: - KeychainService
// Provides secure storage using iOS Keychain with Secure Enclave access controls

final class KeychainService {
    
    static let shared = KeychainService()
    
    private let serviceName = "com.app.investordemo"
    
    private init() {}
    
    // MARK: - Store secret in Keychain with access control
    
    func store(secret: String, forKey key: String, requireBiometric: Bool = false) throws {
        guard let data = secret.data(using: .utf8) else {
            throw SecureSecretsError.dataConversionFailed
        }
        
        // Delete any existing item first
        try? delete(key: key)
        
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        // Optionally require biometric authentication for access
        if requireBiometric {
            var error: Unmanaged<CFError>?
            guard let accessControl = SecAccessControlCreateWithFlags(
                kCFAllocatorDefault,
                kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                .biometryCurrentSet,
                &error
            ) else {
                throw SecureSecretsError.keychainWriteFailed(-1)
            }
            query[kSecAttrAccessControl as String] = accessControl
            query.removeValue(forKey: kSecAttrAccessible as String)
        }
        
        let status = SecItemAdd(query as CFDictionary, nil)
        
        guard status == errSecSuccess else {
            throw SecureSecretsError.keychainWriteFailed(status)
        }
    }
    
    // MARK: - Retrieve secret from Keychain
    
    func retrieve(key: String) throws -> String {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw SecureSecretsError.keychainReadFailed
        }
        
        guard let string = String(data: data, encoding: .utf8) else {
            throw SecureSecretsError.dataConversionFailed
        }
        
        return string
    }
    
    // MARK: - Delete secret from Keychain
    
    func delete(key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw SecureSecretsError.keychainDeleteFailed(status)
        }
    }
    
    // MARK: - Check if a key exists
    
    func exists(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: false,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }
}

// MARK: - SecretsManager
// Loads secrets from environment variables or secure remote config,
// then caches them in the Keychain. NEVER embeds secrets in source code.

final class SecretsManager {
    
    static let shared = SecretsManager()
    
    private let keychain = KeychainService.shared
    
    // Keychain storage keys (these are NOT the secrets themselves)
    private enum Keys {
        static let googleMapsAPIKey = "google_maps_api_key"
        static let stripePublishableKey = "stripe_publishable_key"
        static let stripeSecretKey = "stripe_secret_key"
    }
    
    // Environment variable names
    private enum EnvVars {
        static let googleMapsAPIKey = "GOOGLE_MAPS_API_KEY"
        static let stripePublishableKey = "STRIPE_PUBLISHABLE_KEY"
        static let stripeSecretKey = "STRIPE_SECRET_KEY"
    }
    
    private init() {}
    
    // MARK: - Bootstrap: Load secrets from environment into Keychain
    // Call this once at app startup (e.g., from a CI/CD injected environment
    // or from a secure remote configuration service).
    
    func bootstrapFromEnvironment() throws {
        try loadAndStore(envVar: EnvVars.googleMapsAPIKey, keychainKey: Keys.googleMapsAPIKey)
        try loadAndStore(envVar: EnvVars.stripePublishableKey, keychainKey: Keys.stripePublishableKey)
        // Stripe secret key should NEVER be on the client in production.
        // Only load if present (for server-side or controlled demo environments).
        if let stripeSecret = ProcessInfo.processInfo.environment[EnvVars.stripeSecretKey] {
            try keychain.store(secret: stripeSecret, forKey: Keys.stripeSecretKey)
        }
    }
    
    // MARK: - Bootstrap from remote secure config (preferred for demos)
    // Fetches secrets from a secure backend endpoint rather than embedding them.
    
    func bootstrapFromRemoteConfig(endpoint: URL, authToken: String) async throws {
        var request = URLRequest(url: endpoint)
        request.httpMethod = "GET"
        request.setValue("Bearer \(authToken)", forHTTPHeaderField: "Authorization")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        let (data, response) = try await URLSession.shared.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw SecureSecretsError.keychainReadFailed
        }
        
        let config = try JSONDecoder().decode(RemoteConfig.self, from: data)
        
        try keychain.store(secret: config.googleMapsAPIKey, forKey: Keys.googleMapsAPIKey)
        try keychain.store(secret: config.stripePublishableKey, forKey: Keys.stripePublishableKey)
    }
    
    // MARK: - Accessors
    
    var googleMapsAPIKey: String {
        get throws {
            try keychain.retrieve(key: Keys.googleMapsAPIKey)
        }
    }
    
    var stripePublishableKey: String {
        get throws {
            try keychain.retrieve(key: Keys.stripePublishableKey)
        }
    }
    
    // MARK: - Validation
    
    var isConfigured: Bool {
        keychain.exists(key: Keys.googleMapsAPIKey) &&
        keychain.exists(key: Keys.stripePublishableKey)
    }
    
    // MARK: - Cleanup
    
    func clearAllSecrets() throws {
        try keychain.delete(key: Keys.googleMapsAPIKey)
        try keychain.delete(key: Keys.stripePublishableKey)
        try keychain.delete(key: Keys.stripeSecretKey)
    }
    
    // MARK: - Private Helpers
    
    private func loadAndStore(envVar: String, keychainKey: String) throws {
        guard let value = ProcessInfo.processInfo.environment[envVar], !value.isEmpty else {
            // If not in environment, check if already in keychain from previous bootstrap
            if keychain.exists(key: keychainKey) {
                return
            }
            throw SecureSecretsError.missingEnvironmentVariable(envVar)
        }
        try keychain.store(secret: value, forKey: keychainKey)
    }
}

