// MARK: - SecureTokenStorage.swift
// For storing user authentication tokens securely

final class SecureTokenStorage {
    
    static let shared = SecureTokenStorage()
    
    private let keychain = KeychainService.shared
    
    private enum Keys {
        static let userAuthToken = "user_auth_token"
        static let refreshToken = "user_refresh_token"
    }
    
    private init() {}
    
    // SECURE: Store auth tokens in Keychain (NOT UserDefaults)
    func storeAuthToken(_ token: String) throws {
        try keychain.store(secret: token, forKey: Keys.userAuthToken)
    }
    
    func storeRefreshToken(_ token: String) throws {
        // Use biometric protection for refresh tokens (high-value credential)
        try keychain.store(secret: token, forKey: Keys.refreshToken, requireBiometric: true)
    }
    
    func getAuthToken() throws -> String {
        try keychain.retrieve(key: Keys.userAuthToken)
    }
    
    func getRefreshToken() throws -> String {
        try keychain.retrieve(key: Keys.refreshToken)
    }
    
    func clearTokens() throws {
        try keychain.delete(key: Keys.userAuthToken)
        try keychain.delete(key: Keys.refreshToken)
    }
    
    var hasAuthToken: Bool {
        keychain.exists(key: Keys.userAuthToken)
    }
}

// MARK: - AppDelegate.swift
// Demonstrates secure app initialization

import UIKit

class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        
        do {
            try initializeSecureServices()
        } catch {
            print("⚠️ Failed to initialize services: \(error.localizedDescription)")
            print("ℹ️ Ensure environment variables are set:")
            print("   GOOGLE_MAPS_API_KEY=<your-key>")
            print("   STRIPE_PUBLISHABLE_KEY=<your-key>")
            print("")
            print("   For Xcode: Edit Scheme → Run → Arguments → Environment Variables")
            print("   For CI/CD: Set in your pipeline's secret management")
            
            // Show configuration screen instead of crashing
            showConfigurationRequiredScreen()
            return true
        }
        
        showMainScreen()
        return true
    }
    
    private func initializeSecureServices() throws {
        // Step 1: Load secrets from environment variables into Keychain
        // In production, use bootstrapFromRemoteConfig() instead
        try SecretsManager.shared.bootstrapFromEnvironment()
        
        // Step 2: Initialize SDKs with keys from Keychain
        try GoogleMapsService.shared.initialize()
        try StripePaymentService.shared.initialize()
    }
    
    private func showMainScreen() {
        window = UIWindow(frame: UIScreen.main.bounds)
        window?.rootViewController = UINavigationController(rootViewController: MainViewController())
        window?.makeKeyAndVisible()
    }
    
    private func showConfigurationRequiredScreen() {
        window = UIWindow(frame: UIScreen.main.bounds)
        window?.rootViewController = ConfigurationRequiredViewController()
        window?.makeKeyAndVisible()
    }
}

// MARK: - MainViewController.swift
// Main demo screen with map and payment

class MainViewController: UIViewController {
    
    private lazy var mapContainer: UIView = {
        let view = UIView()
        view.translatesAutoresizingMaskIntoConstraints = false
        view.layer.cornerRadius = 12
        view.clipsToBounds = true
        return view
    }()
    
    private lazy var payButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Pay $9.99", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        button.backgroundColor = .systemBlue
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 12
        button.translatesAutoresizingMaskIntoConstraints = false
        button.addTarget(self, action: #selector(handlePayment), for: .touchUpInside)
        return button
    }()
    
    private lazy var statusLabel: UILabel = {
        let label = UILabel()
        label.text = "Services initialized securely ✅"
        label.textAlignment = .center
        label.font = .systemFont(ofSize: 14)
        label.textColor = .systemGreen
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private lazy var securityInfoLabel: UILabel = {
        let label = UILabel()
        label.text = "🔒 API keys loaded from Keychain\n🔒 No hardcoded secrets in source"
        label.numberOfLines = 0
        label.textAlignment = .center
        label.font = .systemFont(ofSize: 12)
        label.textColor = .secondaryLabel
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Investor Demo"
        view.backgroundColor = .systemBackground
        setupUI()
        setupMap()
    }
    
    private func setupUI() {
        view.addSubview(mapContainer)
        view.addSubview(payButton)
        view.addSubview(statusLabel)
        view.addSubview(securityInfoLabel)
        
        NSLayoutConstraint.activate([
            statusLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 8),
            statusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            statusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            
            mapContainer.topAnchor.constraint(equalTo: statusLabel.bottomAnchor, constant: 16),
            mapContainer.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            mapContainer.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            mapContainer.heightAnchor.constraint(equalTo: view.heightAnchor, multiplier: 0.5),
            
            payButton.topAnchor.constraint(equalTo: mapContainer.bottomAnchor, constant: 24),
            payButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            payButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            payButton.heightAnchor.constraint(equalToConstant: 50),
            
            securityInfoLabel.topAnchor.constraint(equalTo: payButton.bottomAnchor, constant: 16),
            securityInfoLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            securityInfoLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
        ])
    }
    
    private func setupMap() {
        let mapView = GoogleMapsService.shared.createMapView(frame: .zero)
        mapView.translatesAutoresizingMaskIntoConstraints = false
        mapContainer.addSubview(mapView)
        
        NSLayoutConstraint.activate([
            mapView.topAnchor.constraint(equalTo: mapContainer.topAnchor),
            mapView.leadingAnchor.constraint(equalTo: mapContainer.leadingAnchor),
            mapView.trailingAnchor.constraint(equalTo: mapContainer.trailingAnchor),
            mapView.bottomAnchor.constraint(equalTo: mapContainer.bottomAnchor),
        ])
    }
    
    @objc private func handlePayment() {
        payButton.isEnabled = false
        payButton.setTitle("Processing...", for: .normal)
        
        Task {
            do {
                let result = try await StripePaymentService.shared.createPaymentIntent(
                    amount: 999, // $9.99 in cents
                    currency: "usd"
                )
                
                await MainActor.run {
                    payButton.isEnabled = true
                    payButton.setTitle("Pay $9.99", for: .normal)
                    
                    let alert = UIAlertController(
                        title: "Payment \(result.status.rawValue.capitalized)!",
                        message: "ID: \(result.id)\nAmount: $\(String(format: "%.2f", Double(result.amount) / 100.0))",
                        preferredStyle: .alert
                    )
                    alert.addAction(UIAlertAction(title: "OK", style: .default))
                    self.present(alert, animated: true)
                }
            } catch {
                await MainActor.run {
                    payButton.isEnabled = true
                    payButton.setTitle("Pay $9.99", for: .normal)
                    
                    let alert = UIAlertController(
                        title: "Payment Failed",
                        message: error.localizedDescription,
                        preferredStyle: .alert
                    )
                    alert.addAction(UIAlertAction(title: "OK", style: .default))
                    self.present(alert, animated: true)
                }
            }
        }
    }
}

