        descriptionLabel.text = """
        API keys must be provided via environment variables.
        
        In Xcode:
        1. Edit Scheme → Run → Arguments
        2. Add Environment Variables:
           • GOOGLE_MAPS_API_KEY
           • STRIPE_PUBLISHABLE_KEY
        
