        let manualConfigButton = UIButton(type: .system)
        manualConfigButton.setTitle("Enter Keys Manually (Demo Only)", for: .normal)
        manualConfigButton.addTarget(self, action: #selector(showManualEntry), for: .touchUpInside)
        
        stackView.addArrangedSubview(iconLabel)
        stackView.addArrangedSubview(titleLabel)
        stackView.addArrangedSubview(descriptionLabel)
        stackView.addArrangedSubview(manualConfigButton)
        
