        NSLayoutConstraint.activate([
            stackView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(greaterThanOrEqualTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(lessThanOrEqualTo: view.trailingAnchor, constant: -32),
        ])
    }
    
    @objc private func showManualEntry() {
        let alert = UIAlertController(
            title: "Enter API Keys",
            message: "Keys will be stored securely in the iOS Keychain.",
            preferredStyle: .alert
        )
        
        alert.addTextField { field in
            field.placeholder = "Google Maps API Key"
            field.isSecureTextEntry = true
            field.autocorrectionType = .no
        }
        
        alert.addTextField { field in
            field.placeholder = "Stripe Publishable Key"
            field.isSecureTextEntry = true
            field.autocorrectionType = .no
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Save & Continue", style: .default) { [weak self] _ in
            guard let googleKey = alert.textFields?[0].text, !googleKey.isEmpty,
                  let stripeKey = alert.textFields?[1].text, !stripeKey.isEmpty else {
                return
            }
            
            do {
                let keychain = KeychainService.shared
                try keychain.store(secret: googleKey, forKey: "google_maps_api_key")
                try keychain.store(secret: stripeKey, forKey: "stripe_publishable_key")
                
                try GoogleMapsService.shared.initialize()
                try StripePaymentService.shared.initialize()
                
                // Transition to main screen
                let nav = UINavigationController(rootViewController: MainViewController())
                nav.modalPresentationStyle = .fullScreen
                self?.present(nav, animated: true)
            } catch {
                let errorAlert = UIAlertController(
                    title: "Error",
                    message: error.localizedDescription,
                    preferredStyle: .alert
                )
                errorAlert.addAction(UIAlertAction(title: "OK", style: .default))
                self?.present(errorAlert, animated: true)
            }
        })
        
        present(alert, animated: true)
    }
}

// MARK: - SECURITY DOCUMENTATION
/*
 ============================================================
 SECURITY ARCHITECTURE - READ BEFORE MODIFYING
 ============================================================
 
 ✅ WHAT THIS CODE DOES (SECURE):
 
 1. API keys are loaded from ENVIRONMENT VARIABLES at runtime,
    then stored in the iOS KEYCHAIN (hardware-backed secure storage).
 
 2. The Keychain uses kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
    meaning secrets cannot be extracted from device backups.
 
 3. High-value tokens (refresh tokens) can optionally require
    biometric authentication via Secure Enclave.
 
 4. For investor demos, keys can be entered manually through a
    secure input screen — they go directly to Keychain, never
    to disk or UserDefaults.
 
 5. A remote config option is provided for fetching secrets from
    a secure backend, which is the recommended approach for
    distributing demo builds.
 
 ❌ WHAT THIS CODE DOES NOT DO (AND NEVER SHOULD):
 
 1. NO hardcoded API keys anywhere in source code.
    Even "test" keys in source get committed to git, leaked in
    IPA files, and extracted by anyone with basic tools.
 
 2. NO secrets in UserDefaults, plist files, or plain text storage.
    UserDefaults is an unencrypted plist readable on jailbroken devices.
 
 3. NO Stripe secret keys on the client.
    Payment intents must be created server-side. The client only
    uses the publishable key.
 
 ============================================================
 SETUP FOR INVESTOR DEMO BUILDS:
 ============================================================
 
 Option A (Xcode):
   Edit Scheme → Run → Arguments → Environment Variables:
   GOOGLE_MAPS_API_KEY = <key>
   STRIPE_PUBLISHABLE_KEY = <key>
 
 Option B (CI/CD - Recommended):
   Store keys in your CI/CD secret manager (GitHub Secrets,
   Bitrise Secrets, etc.) and inject as env vars during build.
 
 Option C (Remote Config - Best for distributed demos):
